}
{
  lines[NR] = $0
}
END {
  i = 1
  while (i <= NR) {
    if (!is_file(lines[i])) {
      print lines[i]
      i++
      continue
    }
    cp = connector_pos(lines[i])
    # Collect consecutive file siblings at same connector position
    n = 0
