    expect(container.innerHTML).toBe('');
  });
  it('renders improving trend with positive percentage', () => {
    const trend: MetricTrend = {
      direction: 'improving',
      delta: 0.05,
      percentChange: 5.3,
      currentValue: 0.85,
      previousValue: 0.8,
      aggregation: 'avg',
      lowSampleWarning: false,
    };
    render(<TrendIndicator trend={trend} />);
    expect(screen.getByText(/\+5.3%/)).toBeInTheDocument();
    expect(screen.getByLabelText(/improving/)).toBeInTheDocument();
  });
  it('renders degrading trend with negative percentage', () => {
    const trend: MetricTrend = {
      direction: 'degrading',
      delta: -0.05,
      percentChange: -3.1,
      currentValue: 0.75,
      previousValue: 0.8,
      aggregation: 'avg',
      lowSampleWarning: false,
    };
    render(<TrendIndicator trend={trend} />);
    expect(screen.getByText(/-3.1%/)).toBeInTheDocument();
  });
  it('shows low sample warning indicator', () => {
    const trend: MetricTrend = {
      direction: 'stable',
      delta: 0,
      percentChange: 0,
      currentValue: 0.8,
      previousValue: 0.8,
      aggregation: 'avg',
      lowSampleWarning: true,
