    function ComboConsumer() {
      useShortcut('g h', 'Go home', 'nav', action);
      return null;
    }
    render(
      <KeyboardNavProvider>
        <ComboConsumer />
      </KeyboardNavProvider>,
    );
    act(() => {
      fireEvent.keyDown(document, { key: 'g' });
      fireEvent.keyDown(document, { key: 'x' });
    });
    act(() => {
