import {
  computeDashboardSummary,
  computeRoleView,
  type RoleViewType,
} from '../../../../dist/lib/quality/quality-metrics.js';
import type { EvaluationResult } from '../../../../dist/backends/index.js';
import { computeCQI } from '../../../../dist/lib/quality/quality-feature-engineering.js';
