interface AgentScoreSummaryProps {
  handoffScore: number;
  avgRelevance: number;
  completeness: number;
}
const SCORES = [
  { label: 'Handoff Score', metricName: 'handoff' },
  { label: 'Avg Relevance', metricName: 'relevance' },
  { label: 'Completeness', metricName: 'completeness' },
