}import React, { useState, useCallback, useMemo, useRef } from 'react';
import { WorkflowGraphView } from './WorkflowGraph.js';
import { WorkflowTimeline } from './WorkflowTimeline.js';
import type { WorkflowGraph } from '../types/workflow-graph.js';
import type { MultiAgentEvaluation } from '../types.js';
import { agentColor, fmtDuration } from '../lib/quality-utils.js';
import { WORKFLOW_FILTER_MIN_AGENTS } from '../lib/constants.js';
type WorkflowTab = 'dag' | 'timeline';
interface AgentWorkflowViewProps {
  graph: WorkflowGraph;
  evaluation?: MultiAgentEvaluation;
  onNodeClick?: (nodeId: string) => void;
  height?: number;
}
const TAB_LABELS: Record<WorkflowTab, string> = {
  dag: 'DAG',
  timeline: 'Timeline',
};
const TABS: WorkflowTab[] = ['dag', 'timeline'];
export function AgentWorkflowView({
  graph,
  evaluation,
  onNodeClick,
  height = 600,
}: AgentWorkflowViewProps) {
  const [activeTab, setActiveTab] = useState<WorkflowTab>('dag');
  const agentNames = useMemo(
    () => [...new Set((evaluation?.turns ?? []).map(t => t.agentName ?? 'unknown'))],
    [evaluation?.turns],
  );
  const [selectedAgents, setSelectedAgents] = useState<ReadonlySet<string> | null>(null);
  const [minDurationMs, setMinDurationMs] = useState(0);
  const [errorsOnly, setErrorsOnly] = useState(false);
  const [showCriticalPath, setShowCriticalPath] = useState(false);
  const graphContainerRef = useRef<HTMLDivElement>(null);
  const effectiveSelected: ReadonlySet<string> = useMemo(
    () => selectedAgents ?? new Set(agentNames),
    [selectedAgents, agentNames.join(',')],
  );
  const maxDurationMs = useMemo(
    () => Math.max(0, ...graph.nodes.map(n => n.durationMs)),
    [graph.nodes],
  );
  const criticalPathSet = useMemo((): ReadonlySet<string> | undefined => {
    if (!showCriticalPath || graph.nodes.length === 0 || graph.rootNodeId === null) return undefined;
    const adj = new Map<string, string[]>(graph.nodes.map(n => [n.id, []]));
    for (const edge of graph.edges) {
      adj.get(edge.source)?.push(edge.target);
    }
    const dur = new Map(graph.nodes.map(n => [n.id, n.durationMs]));
    function dfs(nodeId: string, visiting: Set<string>): [string[], number] {
      if (visiting.has(nodeId)) return [[], 0];
      visiting.add(nodeId);
      let bestPath: string[] = [];
      let bestCost = 0;
      for (const child of adj.get(nodeId) ?? []) {
        const [childPath, childCost] = dfs(child, visiting);
        if (childCost > bestCost) {
          bestCost = childCost;
          bestPath = childPath;
        }
      }
      visiting.delete(nodeId);
      return [[nodeId, ...bestPath], (dur.get(nodeId) ?? 0) + bestCost];
    }
    const [path] = dfs(graph.rootNodeId, new Set());
    return new Set(path);
  }, [showCriticalPath, graph.nodes, graph.edges, graph.rootNodeId]);
  const filteredNodeIds = useMemo((): ReadonlySet<string> | undefined => {
    const hasAgentFilter = selectedAgents !== null;
    const hasDurFilter = minDurationMs > 0;
    const hasErrFilter = errorsOnly;
    if (!hasAgentFilter && !hasDurFilter && !hasErrFilter) return undefined;
    let result = new Set(graph.nodes.map(n => n.id));
    if (hasAgentFilter) {
      result = new Set([...result].filter(id => selectedAgents!.has(id)));
    }
    if (hasDurFilter) {
      const durPass = new Set(graph.nodes.filter(n => n.durationMs >= minDurationMs).map(n => n.id));
      result = new Set([...result].filter(id => durPass.has(id)));
    }
    if (hasErrFilter) {
      const errPass = new Set(graph.nodes.filter(n => n.hasError).map(n => n.id));
      result = new Set([...result].filter(id => errPass.has(id)));
    }
    return result;
  }, [selectedAgents, minDurationMs, errorsOnly, graph.nodes]);
  const toggleAgent = useCallback((name: string) => {
    setSelectedAgents(prev => {
      const base = prev ?? new Set(agentNames);
      const next = new Set(base);
      if (next.has(name)) {
        next.delete(name);
      } else {
        next.add(name);
      }
      if (next.size === agentNames.length) return null;
      return next;
    });
  }, [agentNames]);
  const selectAll = useCallback(() => setSelectedAgents(null), []);
  const handleExport = useCallback(async () => {
    const el = graphContainerRef.current;
    if (!el) return;
    const { toPng } = await import('html-to-image');
    const dataUrl = await toPng(el, { cacheBust: true });
    const link = document.createElement('a');
    link.href = dataUrl;
    link.download = 'workflow-graph.png';
    link.click();
  }, []);
  const showFilter = agentNames.length >= WORKFLOW_FILTER_MIN_AGENTS;
  const showControls = graph.nodes.length > 0;
  const sliderStep = Math.max(1, Math.round(maxDurationMs / 200));
  return (
    <div>
      <div
        role="tablist"
        aria-label="Workflow view"
        className="flex-center gap-0 workflow-tabs"
      >
        {TABS.map(tab => (
          <button
            key={tab}
            type="button"
            role="tab"
            id={`workflow-tab-${tab}`}
            aria-selected={activeTab === tab}
            aria-controls={`workflow-panel-${tab}`}
            onClick={() => setActiveTab(tab)}
            className="btn-reset workflow-tab"
          >
            {TAB_LABELS[tab]}
          </button>
        ))}
      </div>
      {showFilter && (
        <div className="workflow-filter" role="group" aria-label="Filter agents">
          {agentNames.map(name => {
            const color = agentColor(name, agentNames);
            const active = effectiveSelected.has(name);
            return (
              <button
                key={name}
                type="button"
                className="btn-reset eval-filter-chip workflow-filter__chip mono-xs"
                style={{ '--chip-color': color } as React.CSSProperties}
                data-active={active || undefined}
                aria-pressed={active}
                onClick={() => toggleAgent(name)}
              >
                {name}
              </button>
            );
          })}
          {selectedAgents !== null && (
            <button
              type="button"
              className="btn-reset workflow-filter__reset text-xs text-muted"
              onClick={selectAll}
            >
              All
            </button>
          )}
        </div>
      )}
      {showControls && (
        <div className="workflow-filter__controls" role="group" aria-label="Graph controls">
          <label className="workflow-filter__label">
            Min duration
            <input
              type="range"
              min={0}
              max={maxDurationMs}
              step={sliderStep}
              value={minDurationMs}
              onChange={e => setMinDurationMs(Number(e.target.value))}
              className="workflow-filter__slider"
              aria-label={`Minimum agent duration: ${fmtDuration(minDurationMs)}`}
            />
            <span className="workflow-filter__slider-value mono-xs">
              {minDurationMs > 0 ? `≥ ${fmtDuration(minDurationMs)}` : 'any'}
            </span>
          </label>
          <button
            type="button"
            className="btn-reset eval-filter-chip workflow-filter__chip eval-filter-chip--error"
            data-active={errorsOnly || undefined}
            aria-pressed={errorsOnly}
            onClick={() => setErrorsOnly(v => !v)}
          >
            Errors only
          </button>
          <button
            type="button"
            className="btn-reset eval-filter-chip workflow-filter__chip eval-filter-chip--accent"
            data-active={showCriticalPath || undefined}
            aria-pressed={showCriticalPath}
            onClick={() => setShowCriticalPath(v => !v)}
          >
            Critical path
          </button>
          <button
            type="button"
            className="btn-reset workflow-filter__export mono-xs"
            onClick={handleExport}
            aria-label="Export graph as PNG"
          >
            Export PNG
          </button>
        </div>
      )}
      <div
        role="tabpanel"
        id="workflow-panel-dag"
        aria-labelledby="workflow-tab-dag"
        hidden={activeTab !== 'dag'}
      >
        <WorkflowGraphView
          graph={graph}
          onNodeClick={onNodeClick}
          height={height}
          selectedAgents={filteredNodeIds}
          criticalPath={criticalPathSet}
          containerRef={graphContainerRef}
        />
      </div>
      <div
        role="tabpanel"
        id="workflow-panel-timeline"
        aria-labelledby="workflow-tab-timeline"
        hidden={activeTab !== 'timeline'}
      >
        <WorkflowTimeline
          turns={evaluation?.turns ?? []}
          handoffs={evaluation?.handoffs ?? []}
          agentNames={agentNames}
          selectedAgents={showFilter ? effectiveSelected : undefined}
        />
      </div>
    </div>
  );
}import { Link } from 'wouter';
import type { CSSProperties } from 'react';
import { formatScore } from '../lib/quality-utils.js';
import type { TriggeredAlert } from '../types.js';
type AlertWithMeta = TriggeredAlert & { metricName?: string };
function SimpleAlertItem({ alert }: { alert: AlertWithMeta }) {
  return (
    <li className="alert-item" data-status={alert.severity}>
      <div className="alert-message">{alert.message}</div>
      <div className="alert-meta text-secondary text-xs">
        {alert.aggregation} = {formatScore(alert.actualValue)} (threshold: {formatScore(alert.threshold)})
      </div>
      {alert.remediationHints && alert.remediationHints.length > 0 && (
        <div className="remediation text-xs">
          Hint: {alert.remediationHints[0]}
        </div>
      )}
    </li>
  );
}
function ThresholdBar({ actual, threshold, direction }: {
  actual: number;
  threshold: number;
  direction: 'above' | 'below';
}) {
  const max = Math.max(actual, threshold) * 1.2 || 1;
  const actualPct = Math.max(0, Math.min((actual / max) * 100, 100));
  const thresholdPct = Math.max(0, Math.min((threshold / max) * 100, 100));
  const isViolating = direction === 'below' ? actual < threshold : actual > threshold;
  return (
    <div className="threshold-bar" aria-label={`Actual: ${formatScore(actual)}, Threshold: ${formatScore(threshold)}`}>
      <div
        className="threshold-bar-fill"
        data-violating={isViolating || undefined}
        style={{ '--bar-fill-width': `${actualPct}%` } as CSSProperties}
      />
      <div
        className="threshold-bar-marker"
        style={{ '--bar-marker-left': `${thresholdPct}%` } as CSSProperties}
        title={`Threshold: ${formatScore(threshold)}`}
      />
    </div>
  );
}
function CompoundAlertCard({ alert }: { alert: AlertWithMeta }) {
  return (
    <li className="alert-item alert-compound" data-status={alert.severity}>
      <div className="alert-message">{alert.message}</div>
      <div className="alert-meta text-secondary text-xs">
        {alert.aggregation} = {formatScore(alert.actualValue)} (threshold: {formatScore(alert.threshold)})
      </div>
      <ThresholdBar
        actual={alert.actualValue}
        threshold={alert.threshold}
        direction={alert.direction}
      />
      {alert.remediationHints && alert.remediationHints.length > 0 && (
        <ol className="remediation-list text-xs">
          {alert.remediationHints.map((hint, i) => (
            <li key={i}>{hint}</li>
          ))}
        </ol>
      )}
      {alert.relatedMetrics && alert.relatedMetrics.length > 0 && (
        <div className="alert-related flex-center">
          <span className="text-secondary text-xs">Related:</span>
          {alert.relatedMetrics.map((m) => (
            <Link key={m} href={`/metrics/${m}`} className="alert-metric-link text-xs">
              {m}
            </Link>
          ))}
        </div>
      )}
    </li>
  );
}
export function AlertList({ alerts }: { alerts: AlertWithMeta[] }) {
  if (alerts.length === 0) return null;
  const sorted = [...alerts].sort((a, b) => {
    const order = { critical: 0, warning: 1, info: 2 };
    return (order[a.severity as keyof typeof order] ?? 2) - (order[b.severity as keyof typeof order] ?? 2);
  });
  return (
    <ul className="alert-list">
      {sorted.map((alert, i) =>
        alert.isCompound
          ? <CompoundAlertCard key={`${alert.message}-${i}`} alert={alert} />
          : <SimpleAlertItem key={`${alert.message}-${i}`} alert={alert} />
      )}
    </ul>
  );
}import type { CSSProperties } from 'react';
interface BarIndicatorProps {
  value: number;
  color?: string;
  opacity?: number;
  height?: number;
  trackColor?: string;
  className?: string;
  style?: CSSProperties;
}
export function BarIndicator({
  value,
  color,
  opacity,
  height,
  trackColor,
  className,
  style,
}: BarIndicatorProps) {
  const trackStyle: CSSProperties = {
    ...style,
    '--bar-fill-width': `${value}%`,
    ...(height != null && { '--bar-h': `${height}px` } as CSSProperties),
    ...(trackColor && { '--bar-track-color': trackColor } as CSSProperties),
    ...(color && { '--bar-fill-color': color } as CSSProperties),
    ...(opacity != null && { '--bar-fill-opacity': opacity } as CSSProperties),
  } as CSSProperties;
  return (
    <div
      className={className ? `mini-bar ${className}` : 'mini-bar'}
      style={trackStyle}
    >
      <div className="mini-bar-fill" />
    </div>
  );
}import { MetaItem } from './MetaItem.js';
interface ChainOfThoughtPanelProps {
  explanation?: string;
  evaluator?: string;
}
export function ChainOfThoughtPanel({ explanation, evaluator }: ChainOfThoughtPanelProps) {
