            <span className="text-secondary">Agreement</span>
            <span
              className="mono agreement-value"
              data-band={evaluatorAgreement > SCORE_THRESHOLD_GREEN ? 'excellent' : evaluatorAgreement > SCORE_THRESHOLD_YELLOW ? 'adequate' : undefined}
