    </div>
  );
}import { useMemo } from 'react';
import type { CSSProperties } from 'react';
import { scaleSequential } from 'd3-scale';
import { interpolateRdYlGn } from 'd3-scale-chromatic';
import { formatScore } from '../lib/quality-utils.js';
import { HEATMAP_ROW_HEADER_WIDTH, HEATMAP_COL_HEADER_HEIGHT, SCORE_CHIP_PRECISION, SCORE_DISPLAY_PRECISION } from '../lib/constants.js';
import type { CorrelationFeature } from '../types.js';
interface CorrelationHeatmapProps {
  correlations: CorrelationFeature[];
  metrics: string[];
  onCellClick?: (rowMetric: string, colMetric: string) => void;
}
const CONTRAST_DARK = '#111';
const CONTRAST_LIGHT = '#fff';
const SHORT_NAMES: Record<string, string> = {
  faithfulness: 'Faith',
  relevance: 'Relev',
  coherence: 'Coher',
  safety: 'Safety',
  instruction_adherence: 'Instr',
  tool_accuracy: 'Tool',
  latency: 'Latency',
};
function shortName(metric: string): string {
  return SHORT_NAMES[metric] ?? metric.slice(0, 6);
}
function contrastText(pearsonR: number): string {
  const bg = colorScale(pearsonR);
  const m = bg.match(/(\d+)/g);
  if (!m || m.length < 3) return CONTRAST_DARK;
  const [r, g, b] = m.map(Number);
  const toLinear = (c: number) => {
    const s = c / 255;
    return s <= 0.03928 ? s / 12.92 : ((s + 0.055) / 1.055) ** 2.4;
  };
  const L = 0.2126 * toLinear(r) + 0.7152 * toLinear(g) + 0.0722 * toLinear(b);
  return L > 0.18 ? CONTRAST_DARK : CONTRAST_LIGHT;
}
const colorScale = scaleSequential(interpolateRdYlGn).domain([-1, 1]);
function corrKey(a: string, b: string): string {
  return a < b ? `${a}|${b}` : `${b}|${a}`;
}
export function CorrelationHeatmap({ correlations, metrics, onCellClick }: CorrelationHeatmapProps) {
  const n = metrics.length;
  const cols = n + 1;
  const corrMap = useMemo(
    () => new Map(correlations.map(c => [corrKey(c.metricA, c.metricB), c])),
    [correlations],
  );
  return (
    <div
      role="table"
      aria-label="Metric correlation matrix"
      className="gap-half w-full heatmap-grid"
      style={{
        '--heatmap-aspect': `${cols} / ${cols}`,
        '--heatmap-grid-cols': `${HEATMAP_ROW_HEADER_WIDTH}px repeat(${n}, 1fr)`,
        '--heatmap-grid-rows': `${HEATMAP_COL_HEADER_HEIGHT}px repeat(${n}, 1fr)`,
      } as CSSProperties}
    >
      <div role="cell" />
      {metrics.map((m) => (
        <div
          key={`col-${m}`}
          role="columnheader"
          className="text-secondary text-xs font-semibold truncate flex-center"
        >
          {shortName(m)}
        </div>
      ))}
      {metrics.map((rowMetric, ri) => (
        <div key={`row-${rowMetric}`} role="presentation" className="contents">
          <div
            role="rowheader"
            className="text-secondary text-xs font-semibold truncate flex-center heatmap-row-header"
          >
            {shortName(rowMetric)}
          </div>
          {metrics.map((colMetric, ci) => {
            const isDiag = ri === ci;
            const corr = isDiag ? undefined : corrMap.get(corrKey(rowMetric, colMetric));
            const value = isDiag ? 1 : corr?.pearsonR ?? 0;
            const isToxic = corr?.isKnownToxicCombo ?? false;
            const bg = isDiag ? 'var(--bg-surface)' : colorScale(value);
            const tooltip = isDiag
              ? `${rowMetric}: diagonal (1.00)`
              : corr
                ? `${corr.metricA} vs ${corr.metricB}\npearsonR: ${corr.pearsonR.toFixed(SCORE_DISPLAY_PRECISION)}\nlagHours: ${corr.lagHours}\npValue: ${formatScore(corr.pValue)}\nsignificant: ${corr.significant}`
                : `${rowMetric} vs ${colMetric}: no data`;
            return (
              <div
                key={`${ri}-${ci}`}
                role="cell"
                aria-label={`${rowMetric} vs ${colMetric}: ${value.toFixed(SCORE_CHIP_PRECISION)}`}
                data-toxic={isToxic ? 'true' : undefined}
                title={tooltip}
                onClick={!isDiag && onCellClick ? () => onCellClick(rowMetric, colMetric) : undefined}
                className={`mono-xs font-medium flex-center justify-center heatmap-cell${!isDiag && onCellClick ? ' cursor-pointer' : ''}`}
                style={{
                  '--heatmap-cell-bg': bg,
                  '--heatmap-cell-fg': isDiag ? 'var(--text-secondary)' : contrastText(value),
                } as CSSProperties}
              >
                {value.toFixed(SCORE_CHIP_PRECISION)}
              </div>
            );
          })}
        </div>
      ))}
    </div>
  );
}import { memo, useState, useMemo, type CSSProperties } from 'react';
import type { CoverageCell, CoverageGap, CoverageStatus } from '../types.js';
import { truncateId, plural, formatPercent } from '../lib/quality-utils.js';
import {
  COVERAGE_GRID_HEADER_WIDTH, COVERAGE_GRID_CELL_SIZE,
  COVERAGE_GRID_MAX_INPUTS,
} from '../lib/constants.js';
import { EmptyState } from './EmptyState.js';
interface CoverageGridProps {
  metrics: string[];
  inputs: string[];
  cells: CoverageCell[];
  gaps: CoverageGap[];
  overallCoveragePercent: number;
}
const STATUS_COLORS: Record<CoverageStatus, string> = {
  covered: 'var(--score-good, #0072B2)',
  partial: 'var(--score-fair, #E69F00)',
  missing: 'var(--score-poor, #D55E00)',
};
const COVERAGE_STATUSES = Object.keys(STATUS_COLORS) as CoverageStatus[];
function CoverageGridInner({ metrics, inputs, cells, gaps, overallCoveragePercent }: CoverageGridProps) {
  const [hovered, setHovered] = useState<{ metric: string; input: string } | null>(null);
  const cellMap = useMemo(() => {
    const map = new Map<string, CoverageCell>();
    if (!Array.isArray(cells)) return map;
    for (const cell of cells) {
      map.set(`${cell.metric}|${cell.input}`, cell);
    }
    return map;
  }, [cells]);
  if (metrics.length === 0 || inputs.length === 0) {
    return <EmptyState message="No coverage data available." />;
  }
  const displayInputs = inputs.slice(0, COVERAGE_GRID_MAX_INPUTS);
  const truncated = inputs.length > COVERAGE_GRID_MAX_INPUTS;
  return (
    <div role="region" aria-label="Evaluation coverage heatmap">
      <div className="flex-center mb-3 gap-3">
        <span className="mono-xl font-semibold">
          {formatPercent(overallCoveragePercent)}
        </span>
        <span className="text-secondary text-base">
          coverage ({metrics.length} metrics x {inputs.length} inputs)
        </span>
      </div>
      <div className="mb-3 text-xs flex-wrap gap-4">
        {COVERAGE_STATUSES.map(status => (
          <div key={status} className="flex-center gap-1">
            <div
              className="coverage-legend-swatch"
              style={{ '--coverage-status-color': STATUS_COLORS[status] } as CSSProperties}
            />
            <span>{status}</span>
          </div>
        ))}
      </div>
      <div className="overflow-x-auto">
        <div
          role="table"
          aria-label="Coverage matrix"
          className="coverage-grid gap-half"
          style={{
            '--coverage-grid-cols': `${COVERAGE_GRID_HEADER_WIDTH}px repeat(${displayInputs.length}, ${COVERAGE_GRID_CELL_SIZE}px)`,
          } as CSSProperties}
        >
          <div role="row" className="contents">
            <div role="columnheader" className="text-xs font-semibold" />
            {displayInputs.map(input => (
              <div
                key={input}
                role="columnheader"
                title={input}
                className="text-secondary text-2xs coverage-header-cell"
              >
                {truncateId(input, 8)}
              </div>
            ))}
          </div>
          {metrics.map(metric => (
            <div key={metric} role="row" className="contents">
              <div
                role="rowheader"
                className="text-xs flex-center truncate font-medium"
                title={metric}
              >
                {metric}
              </div>
              {displayInputs.map(input => {
                const cell = cellMap.get(`${metric}|${input}`);
                const status = cell?.status ?? 'missing';
                const count = cell?.count ?? 0;
                const isHovered = hovered?.metric === metric && hovered?.input === input;
                return (
                  <div
                    key={input}
                    role="cell"
                    aria-label={`${metric} / ${truncateId(input)}: ${status} (${count})`}
                    title={`${metric} / ${truncateId(input)}: ${plural(count, 'evaluation')}`}
                    onMouseEnter={() => setHovered({ metric, input })}
                    onMouseLeave={() => setHovered(null)}
                    className="mono text-2xs flex-center justify-center coverage-cell"
                    data-hovered={isHovered || undefined}
                    style={{ '--coverage-status-color': STATUS_COLORS[status] } as CSSProperties}
                  >
                    {count > 0 ? count : ''}
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </div>
      {truncated && (
        <p className="text-secondary text-xs mt-2">
          Showing {COVERAGE_GRID_MAX_INPUTS} of {inputs.length} inputs.
        </p>
      )}
      {gaps.length > 0 && (
        <div className="mt-4">
          <h4 className="mb-1-5 text-base">Coverage Gaps</h4>
          <ul className="m-0 text-xs coverage-gap-list">
            {gaps.map(gap => (
              <li key={gap.metric} className="mb-1">
                <strong>{gap.metric}</strong>: {formatPercent(gap.coveragePercent, 0)} covered
                ({plural(gap.missingInputs.length, 'input')} missing)
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}
