import { EvaluationTable, type EvalRow } from './EvaluationTable.js';
import { useMetricEvaluations } from '../hooks/useMetricEvaluations.js';
import type { Period } from '../types.js';
export function EvaluationDetail({
  worst,
  best,
  metricName,
  period,
}: {
  worst: EvalRow[];
  best: EvalRow[];
  metricName?: string;
  period?: Period;
}) {
  const [showAll, setShowAll] = useState(false);
  const [prevMetric, setPrevMetric] = useState(metricName);
  if (prevMetric !== metricName) {
    setPrevMetric(metricName);
    setShowAll(false);
  }
  const { data, isLoading } = useMetricEvaluations(metricName, period, {
    limit: 200,
    enabled: showAll && !!metricName,
  });
  const topEvals: EvalRow[] = [...worst, ...best];
  const displayEvals = showAll && data ? data.rows : topEvals;
  return (
    <div>
      <EvaluationTable evaluations={displayEvals} />
      {metricName && (
        <div className="flex-center gap-3 mt-3">
          {!showAll ? (
            <button
              type="button"
              onClick={() => setShowAll(true)}
              className="text-xs cursor-pointer btn-reset btn-xs text-accent"
            >
              Show all evaluations
            </button>
          ) : isLoading ? (
            <span className="text-secondary text-xs">Loading...</span>
          ) : data ? (
            <span className="text-secondary text-xs">
              Showing {data.rows.length} of {data.total} evaluations
            </span>
          ) : null}
        </div>
      )}
    </div>
  );
}import { Link } from 'wouter';
import { ScoreBadge } from './ScoreBadge.js';
import { routes } from '../lib/routes.js';
import { SCORE_CHIP_PRECISION } from '../lib/constants.js';
import type { EvaluationResult } from '../types.js';
interface EvaluationEventOverlayProps {
  evaluations: EvaluationResult[];
  traceId?: string;
}
export function EvaluationEventOverlay({ evaluations, traceId }: EvaluationEventOverlayProps) {
  if (evaluations.length === 0) return null;
  const byName = new Map<string, EvaluationResult[]>();
  for (const ev of evaluations) {
    const name = ev.evaluationName;
    if (!byName.has(name)) byName.set(name, []);
    byName.get(name)!.push(ev);
  }
  return (
    <div className="flex-wrap gap-2">
      {[...byName.entries()].map(([name, evs]) => {
        const avg = evs.reduce((s, e) => s + (e.scoreValue ?? 0), 0) / evs.length;
        const card = (
          <div className={`flex-center gap-1-5 surface-elevated eval-overlay-card${traceId ? ' eval-summary-card' : ''}`}>
            <span className="text-xs">{name}</span>
            <ScoreBadge score={avg} metricName={name} label={avg.toFixed(SCORE_CHIP_PRECISION)} />
            <span className="text-muted text-2xs">({evs.length})</span>
          </div>
        );
        if (traceId) {
          return (
            <Link
              key={name}
              href={routes.evaluationDetail(traceId, name)}
              className="link-plain"
            >
              {card}
            </Link>
          );
        }
        return <div key={name}>{card}</div>;
      })}
    </div>
  );
}import { Link } from 'wouter';
