              tick={CHART_AXIS_TICK}
              stroke={CHART_COLORS.grid}
            />
            <YAxis
              domain={[yMin - yPad, yMax + yPad]}
              tick={CHART_AXIS_TICK}
              stroke={CHART_COLORS.grid}
              tickFormatter={CHART_YAXIS_TICK_FORMATTER}
              width={CHART_YAXIS_WIDTH}
