export const CHART_YAXIS_TICK_FORMATTER = (v: number): string => v.toFixed(2);import { readFileSync, existsSync, createReadStream } from 'fs';
import { createInterface } from 'readline';
import type { z } from 'zod';
export async function* streamJsonlWithValidation<T>(
  filePath: string,
  schema: z.ZodType<T>
): AsyncGenerator<T> {
  if (!existsSync(filePath)) return;
  const stream = createReadStream(filePath, 'utf-8');
  const rl = createInterface({
    input: stream,
    crlfDelay: Infinity,
  });
  for await (const line of rl) {
    if (!line.trim()) continue;
    try {
      const parsed = JSON.parse(line);
      const result = schema.safeParse(parsed);
      if (result.success) {
        yield result.data;
      }
    } catch {
    }
  }
}
export async function readJsonlWithValidation<T>(
  filePath: string,
  schema: z.ZodType<T>,
  limit?: number
): Promise<T[]> {
  const results: T[] = [];
  for await (const entry of streamJsonlWithValidation(filePath, schema)) {
    results.push(entry);
    if (limit && results.length >= limit) break;
  }
  return results;
}
export function readJsonlWithValidationSync<T>(
  filePath: string,
  schema: z.ZodType<T>,
  limit?: number
): T[] {
  const results: T[] = [];
  if (!existsSync(filePath)) return results;
  try {
    const content = readFileSync(filePath, 'utf-8');
    const lines = content.trim().split('\n');
    for (const line of lines) {
      if (!line.trim()) continue;
      try {
        const parsed = JSON.parse(line);
        const result = schema.safeParse(parsed);
        if (result.success) {
          results.push(result.data);
          if (limit && results.length >= limit) break;
        }
      } catch {
      }
    }
  } catch {
  }
  return results;
}
export function loadJsonWithValidation<T>(
  filePath: string,
  schema: z.ZodType<T>
): T | null {
  if (!existsSync(filePath)) return null;
  try {
    const content = readFileSync(filePath, 'utf-8');
    const parsed = JSON.parse(content);
    const result = schema.safeParse(parsed);
    if (result.success) {
      return result.data;
    } else {
      throw new Error(`Validation failed: ${result.error.message}`);
    }
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    throw new Error(`Failed to load ${filePath}: ${message}`, { cause: error });
  }
}
export function loadJsonWithValidationSafe<T>(
  filePath: string,
  schema: z.ZodType<T>,
  fallback: T
): T {
  try {
    return loadJsonWithValidation(filePath, schema) ?? fallback;
  } catch {
    return fallback;
  }
}export const routes = {
  evaluationDetail: (traceId: string, metric?: string) =>
