    errorPropagationTurns: 0,
    ...overrides,
  };
}
export function makeSpan(overrides: Partial<TraceSpan> = {}): TraceSpan {
  return {
    traceId: 'trace-1',
    spanId: 'span-1',
    name: 'agent_turn',
    startTimeUnixNano: 1000000000,
    endTimeUnixNano: 2000000000,
    durationMs: 1000,
    attributes: {},
    ...overrides,
