  --border-subtle: #1e2a3a;
  --border-accent: #3b5278;
  --text-primary: #e2e8f0;
  --text-secondary: #94a3b8;
  --text-muted: #475569;
  --text-on-accent: #ffffff;
  --chart-text: #8b949e;
  --chart-line: #58a6ff;
  --status-healthy: #26d97f;
  --status-warning: #e5a00d;
  --status-critical: #f04438;
  --status-no-data: #6b7280;
  --status-good: #34d399;
  --status-poor: #f97316;
  --accent: #3b82f6;
  --accent-hover: #60a5fa;
  --accent-muted: #1e3a5f;
  --score-excellent: var(--status-healthy);
  --score-good: var(--status-good);
  --score-adequate: var(--status-warning);
  --score-poor: var(--status-poor);
  --score-failing: var(--status-critical);
  --font-body: 'IBM Plex Sans', -apple-system, BlinkMacSystemFont, sans-serif;
  --font-mono: 'JetBrains Mono', 'SF Mono', Consolas, monospace;
  --space-px: 1px;
  --space-0-5: 2px;
  --space-1: 4px;
  --space-1-5: 6px;
  --space-2: 8px;
  --space-2-5: 10px;
  --space-3: 12px;
  --space-3-5: 14px;
  --space-4: 16px;
  --space-5: 20px;
  --space-6: 24px;
  --space-8: 32px;
  --space-16: 64px;
  --layout-max-width: 1280px;
  --page-content-max-width: 1100px;
  --bg-status-healthy: #0d1f12;
  --bg-status-warning: #1f1a0d;
  --bg-status-critical: #1f0d0d;
  --border-status-healthy: #1a3a1f;
  --border-status-warning: #3a2f1a;
  --border-status-critical: #3a1a1a;
  --accent-alpha-10: rgba(59, 130, 246, 0.1);
  --accent-alpha-20: rgba(59, 130, 246, 0.2);
  --healthy-alpha-15: rgba(38, 217, 127, 0.15);
  --warning-alpha-15: rgba(229, 160, 13, 0.15);
  --critical-alpha-20: rgba(240, 68, 56, 0.2);
  --critical-alpha-40: rgba(240, 68, 56, 0.4);
  --critical-alpha-60: rgba(240, 68, 56, 0.6);
  --radius-xs: 2px;
  --radius-bar: 3px;
  --radius-sm: 4px;
  --radius: 6px;
  --radius-lg: 8px;
  --radius-pill: 12px;
  --radius-full: 50%;
  --border-width-thick: 2px;
  --border-width-rail: 3px;
  --font-size-2xs: 9px;
  --font-size-xs: 12px;
  --font-size-base: 14px;
  --font-size-md: 16px;
  --font-size-lg: 18px;
  --font-size-xl: 20px;
  --font-size-stat: 22px;
  --font-size-2xl: 24px;
  --font-size-3xl: 36px;
  --bold: 600;
