.session-vitals-strip {
  background: var(--bg-elevated);
  border: 1px solid var(--border-subtle);
  border-bottom: 1px solid var(--border);
  padding: var(--space-3-5) var(--space-6);
  row-gap: var(--space-3);
  margin-bottom: var(--space-0-5);
}
.stat-item {
  flex: 1 1 100px;
  min-width: 80px;
  text-align: center;
}
.stat-value {
  font-size: var(--font-size-stat);
  line-height: 1.1;
}
.stat-label {
  font-size: var(--font-size-xs);
  font-family: var(--font-mono);
  color: var(--text-muted);
  letter-spacing: var(--stat-label-letter-spacing);
  margin-top: var(--space-px);
}
.freq-bar-row {
  display: grid;
  grid-template-columns: 160px 1fr 36px;
  align-items: center;
  gap: var(--space-2-5);
  margin-bottom: var(--space-1-5);
}
.vitals-divider {
  width: 1px;
  background: var(--border-subtle);
  margin: 0 var(--space-2);
  align-self: stretch;
}
.freq-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(340px, 1fr));
  gap: 0 var(--space-8);
}
.view-section {
  margin-bottom: var(--space-8);
}
.refetch-indicator {
  position: fixed;
  top: var(--space-4);
  right: var(--space-4);
  padding: var(--space-2) var(--space-4);
  border-radius: var(--radius);
  font-size: var(--font-size-xs);
  color: var(--text-secondary);
  z-index: 1000;
  animation: fade-in var(--transition-fast);
}
@keyframes fade-in {
  from { opacity: 0; transform: translateY(-8px); }
  to { opacity: 1; transform: translateY(0); }
}
@keyframes toxicPulse {
  0%, 100% { box-shadow: 0 0 0 0 var(--critical-alpha-40); }
  50% { box-shadow: 0 0 6px 2px var(--critical-alpha-60); }
}
.score-badge-wrapper {
  position: relative;
  cursor: default;
}
.score-no-data { color: var(--status-no-data); }
.score-badge-tooltip {
  bottom: calc(100% + var(--space-2));
  border-radius: var(--radius);
  padding: var(--space-2-5) var(--space-3);
  min-width: 200px;
  max-width: 300px;
  z-index: 20;
  white-space: normal;
  animation: fade-in var(--transition-fast);
}
.score-badge-wrapper:hover .score-badge-tooltip,
.score-badge-wrapper:focus-within .score-badge-tooltip {
  display: block;
}
.tooltip-row {
  display: flex;
  justify-content: space-between;
  gap: var(--space-3);
  padding: var(--space-px) 0;
  color: var(--text-primary);
}
.tooltip-row--col { flex-direction: column; }
.tooltip-link {
  display: block;
  margin-top: var(--space-2);
  padding-top: var(--space-1-5);
  border-top: 1px solid var(--border);
}
.cot-panel {
  margin-top: var(--space-1);
}
.cot-summary {
  color: var(--text-secondary);
  cursor: pointer;
  padding: var(--space-1) 0;
  list-style: none;
}
.cot-summary::-webkit-details-marker {
  display: none;
}
.cot-summary::before {
  content: '\25B6';
  display: inline-block;
  margin-right: var(--space-1-5);
  font-size: var(--font-size-2xs);
  transition: transform var(--transition-fast);
}
details[open] > .cot-summary::before {
  transform: rotate(90deg);
}
.cot-content {
  font-size: var(--font-size-xs);
  color: var(--text-primary);
  line-height: 1.6;
  padding: var(--space-2) 0 var(--space-1);
}
.eval-detail-header {
  margin-bottom: var(--space-6);
}
.eval-detail-meta {
  gap: var(--space-4);
  margin-top: var(--space-2);
}
.eval-detail-card {
  margin-bottom: var(--space-4);
}
.eval-overlay-card {
  padding: 4px 8px;
  border-radius: var(--radius);
}
.eval-summary-card {
  cursor: pointer;
  transition: border-color 0.15s;
}
.eval-summary-card.card:hover {
  border-color: var(--accent);
}
.link-plain {
  text-decoration: none;
  color: inherit;
}
.span-row {
  padding-top: var(--space-2);
  padding-bottom: var(--space-2);
  padding-left: var(--span-row-indent, 0);
}
.span-status-icon { color: var(--text-primary); }
.span-status-icon[data-error] { color: var(--status-critical); }
.span-bar {
  height: var(--space-1);
  width: var(--span-bar-width);
  min-width: var(--span-bar-min-width, 0);
  background: var(--status-healthy);
  border-radius: var(--radius-xs);
  margin-top: var(--space-1);
}
.span-bar[data-error] { background: var(--status-critical); }
.quality-live-bar {
  flex-wrap: wrap;
  padding: var(--space-1-5) var(--space-3);
  border-radius: var(--radius);
}
.quality-chip {
  background: color-mix(in srgb, var(--chip-color) 10%, transparent);
  color: var(--chip-color);
}
.quality-chip .dot-xs { background: var(--chip-color); }
.cqi-value {
  font-size: var(--font-size-3xl);
  line-height: 1.2;
  color: var(--cqi-color, var(--text-primary));
}
.cqi-segment { min-width: var(--space-0-5); flex: var(--cqi-segment-flex); background-color: var(--cqi-segment-bg); }
.cqi-segment-bar {
  height: var(--space-2);
  border-radius: var(--radius-sm);
  overflow: hidden;
}
.heatmap-grid { display: grid; aspect-ratio: var(--heatmap-aspect); grid-template-columns: var(--heatmap-grid-cols); grid-template-rows: var(--heatmap-grid-rows); }
.heatmap-row-header {
  justify-content: flex-end;
  padding-right: var(--space-2);
}
.heatmap-cell {
  border-radius: var(--radius-xs);
  min-height: 36px;
  border: none;
  background-color: var(--heatmap-cell-bg);
  color: var(--heatmap-cell-fg);
}
.heatmap-cell[data-toxic] {
  border: var(--border-width-thick) solid var(--score-failing);
  animation: toxicPulse 2s ease-in-out infinite;
}
.metric-card-compact {
  background: var(--bg-card);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius);
  padding: var(--space-2) var(--space-2-5);
  min-width: 140px;
}
.agent-activity-table {
  min-width: 640px;
}
.agent-inv-bar {
  min-width: 48px;
}
.agent-inv-count { min-width: var(--space-8); }
.agent-dot { background: var(--agent-color, var(--border)); }
.agent-err-rate { color: var(--status-critical); }
.agent-err-rate[data-err-status="ok"] { color: var(--status-healthy); }
.agent-err-rate[data-err-status="warn"] { color: var(--status-warning); }
.score-band[data-band="excellent"] { color: var(--score-excellent); }
.score-band[data-band="good"] { color: var(--score-good); }
.score-band[data-band="adequate"] { color: var(--score-adequate); }
.score-band[data-band="poor"] { color: var(--score-poor); }
.score-band[data-band="failing"] { color: var(--score-failing); }
.grid-two-col {
  display: grid;
  grid-template-columns: 1fr 1fr;
}
.score-label-width {
  min-width: var(--space-8);
}
.agent-expanded-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--space-4);
  padding: var(--space-3) 0 var(--space-1);
}
.alert-compound {
  border-left-width: var(--space-1);
  background: var(--bg-elevated);
}
.alert-related {
  flex-wrap: wrap;
  gap: var(--space-2);
  margin-top: var(--space-2);
}
.alert-metric-link {
  font-family: var(--font-mono);
  padding: var(--space-px) var(--space-2);
  border-radius: var(--radius-pill);
  background: var(--accent-alpha-10);
}
.alert-metric-link:hover {
  background: var(--accent-alpha-20);
}
.remediation-list {
  margin-top: var(--space-2);
  padding-left: var(--space-5);
  color: var(--accent);
}
.remediation-list li {
  margin-bottom: var(--space-1);
}
.threshold-bar {
  position: relative;
  height: var(--space-1-5);
  background: var(--bg-card);
  border-radius: var(--radius-bar);
  margin-top: var(--space-2);
  overflow: visible;
}
.threshold-bar-fill,
.variance-bar-fill {
  height: 100%;
  transition: var(--transition-bar);
}
.threshold-bar-fill { width: var(--bar-fill-width); border-radius: var(--radius-bar); background: var(--status-healthy); }
.threshold-bar-fill[data-violating] { background: var(--status-critical); }
.variance-bar-fill  { border-radius: var(--radius-xs); }
.threshold-bar-marker {
  position: absolute;
  top: -3px;
  left: var(--bar-marker-left);
  width: 2px;
  height: 12px;
  background: var(--text-primary);
  border-radius: calc(var(--radius-xs) / 2);
  transform: translateX(-1px);
}
.pipeline-stat {
  gap: var(--space-1);
}
.pipeline-stat .stat-value {
  font-family: var(--font-mono);
  color: var(--text-primary);
  font-weight: var(--light-bold);
}
.funnel-bar {
  width: var(--funnel-width);
  background: var(--funnel-bg, var(--accent));
  border-radius: var(--radius-sm);
  align-items: center;
  justify-content: space-between;
  padding: 0 var(--space-2-5);
  transition: width 0.3s ease;
  min-width: 40px;
  height: 32px;
}
.funnel-dropoff {
  padding-left: var(--space-2-5);
  margin: var(--space-0-5) 0;
  color: var(--text-secondary);
}
.funnel-dropoff[data-warn] {
  color: var(--status-warning);
}
.metric-worst {
  font-size: var(--font-size-xs);
  color: var(--text-muted);
  margin-top: var(--space-2);
  line-height: 1.4;
}
.metric-worst .worst-score {
  color: var(--score-failing);
  font-family: var(--font-mono);
  font-weight: var(--light-bold);
}
.provenance-grid,
.agreement-grid {
  display: grid;
  gap: var(--space-1) var(--space-4);
  font-family: var(--font-mono);
  font-size: var(--font-size-xs);
}
.provenance-grid { grid-template-columns: auto 1fr; }
.provenance-grid .prov-label {
  color: var(--text-secondary);
  font-family: var(--font-body);
  white-space: nowrap;
}
.provenance-grid .prov-value {
  color: var(--text-primary);
  word-break: break-all;
}
.provenance-actions {
  display: flex;
  gap: var(--space-2);
  margin-top: var(--space-3);
}
.provenance-actions button {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  color: var(--accent);
  padding: var(--space-1) var(--space-3);
  border-radius: var(--radius-sm);
  cursor: pointer;
  font-family: var(--font-body);
}
.provenance-actions button:hover {
  background: var(--bg-hover);
  border-color: var(--border-accent);
}
.confidence-header {
  gap: var(--space-2);
  margin-bottom: var(--space-3);
}
.confidence-stats-grid {
  display: grid;
  grid-template-columns: auto 1fr;
  gap: var(--space-1) var(--space-4);
}
.confidence-level-indicator { color: var(--score-failing); }
.confidence-level-indicator[data-level="high"] { color: var(--score-excellent); }
.confidence-level-indicator[data-level="medium"] { color: var(--score-adequate); }
.agreement-value { color: var(--score-failing); }
.agreement-value[data-band="excellent"] { color: var(--score-excellent); }
.agreement-value[data-band="adequate"] { color: var(--score-adequate); }
.confidence-method {
  font-family: var(--font-mono);
  font-size: var(--font-size-xs);
  color: var(--text-muted);
}
.agreement-grid { grid-template-columns: 1fr auto auto; }
.agreement-grid .ag-header {
  color: var(--text-muted);
  font-size: var(--font-size-xs);
  font-family: var(--font-body);
  padding-bottom: var(--space-1);
  border-bottom: 1px solid var(--border-subtle);
}
.agreement-summary .summary-value {
  font-family: var(--font-mono);
  color: var(--text-primary);
}
.variance-bar {
  gap: var(--space-2);
}
.bar-track {
  height: var(--space-1);
  background: var(--bg-surface);
  border-radius: var(--radius-xs);
}
.variance-bar-track {
  flex: 1;
  height: var(--space-1);
  background: var(--bg-surface);
  border-radius: var(--radius-xs);
  overflow: hidden;
}
.mini-bar {
  height: var(--bar-h, 4px);
  background: var(--bar-track-color, var(--bg-surface));
  border-radius: var(--radius-xs);
  overflow: hidden;
}
.mini-bar-fill {
  height: 100%;
  width: var(--bar-fill-width);
  background: var(--bar-fill-color, var(--accent));
  opacity: var(--bar-fill-opacity, 1);
  border-radius: var(--radius-xs);
  transition: var(--transition-bar);
}
.card--empty {
  padding: var(--space-4);
  color: var(--text-muted);
}
.mono      { font-family: var(--font-mono); }
.mono-2xs  { font-family: var(--font-mono); font-size: var(--font-size-2xs); }
.mono-xs   { font-family: var(--font-mono); font-size: var(--font-size-xs); }
.mono-base { font-family: var(--font-mono); font-size: var(--font-size-base); }
.mono-md   { font-family: var(--font-mono); font-size: var(--font-size-md); }
.mono-lg   { font-family: var(--font-mono); font-size: var(--font-size-lg); }
.mono-xl   { font-family: var(--font-mono); font-size: var(--font-size-xl); }
.mono-2xl  { font-family: var(--font-mono); font-size: var(--font-size-2xl); }
.text-2xs  { font-size: var(--font-size-2xs); }
.text-xs   { font-size: var(--font-size-xs); }
.text-base { font-size: var(--font-size-base); }
.text-md   { font-size: var(--font-size-md); }
.text-lg   { font-size: var(--font-size-lg); }
.text-xl   { font-size: var(--font-size-xl); }
.text-2xl  { font-size: var(--font-size-2xl); }
.text-secondary    { color: var(--text-secondary); }
.text-muted        { color: var(--text-muted); }
.text-accent       { color: var(--accent); }
.text-accent-hover { color: var(--accent-hover); }
.text-on-accent    { color: var(--text-on-accent); }
.d-flex         { display: flex; }
.d-grid         { display: grid; }
.d-inline-block { display: inline-block; }
.d-block        { display: block; }
.timeline-svg   { min-width: var(--timeline-min-width); }
.flex-center    { display: flex; align-items: center; }
.align-start    { align-items: flex-start; }
.uppercase { text-transform: uppercase; letter-spacing: var(--label-letter-spacing); }
.font-normal   { font-weight: 400; }
.font-semibold { font-weight: var(--bold); }
.chip { padding: var(--space-px) var(--space-1-5); border-radius: var(--radius-pill); }
.chip-colored {
  color: var(--chip-color);
  background-color: color-mix(in srgb, var(--chip-color) 13%, transparent);
}
.gap-half { gap: var(--space-px); }
.gap-1    { gap: var(--space-1); }
.gap-1-5  { gap: var(--space-1-5); }
.gap-2    { gap: var(--space-2); }
.gap-2-5  { gap: var(--space-2-5); }
.gap-3    { gap: var(--space-3); }
.gap-4    { gap: var(--space-4); }
.gap-5    { gap: var(--space-5); }
.gap-6    { gap: var(--space-6); }
.gap-8    { gap: var(--space-8); }
.gap-16   { gap: var(--space-16); }
.w-full   { width: 100%; }
.min-w-120 { min-width: 120px; }
.m-0    { margin: 0; }
.ml-1   { margin-left: var(--space-1); }
.ml-2   { margin-left: var(--space-2); }
.ml-auto { margin-left: auto; }
.mr-1   { margin-right: var(--space-1); }
.mb-0   { margin-bottom: 0; }
.mb-1   { margin-bottom: var(--space-1); }
.mb-1-5 { margin-bottom: var(--space-1-5); }
.mb-2   { margin-bottom: var(--space-2); }
.mb-2-5 { margin-bottom: var(--space-2-5); }
.mb-3   { margin-bottom: var(--space-3); }
.mb-4   { margin-bottom: var(--space-4); }
.mb-5   { margin-bottom: var(--space-5); }
.mb-6   { margin-bottom: var(--space-6); }
.mt-0-5 { margin-top: var(--space-0-5); }
.mt-1   { margin-top: var(--space-1); }
.mt-2   { margin-top: var(--space-2); }
.mt-3   { margin-top: var(--space-3); }
.mt-4   { margin-top: var(--space-4); }
.my-2   { margin-top: var(--space-2); margin-bottom: var(--space-2); }
.p-4    { padding: var(--space-4); }
.p-4-5  { padding: var(--space-4) var(--space-5); }
.p-6    { padding: var(--space-6); }
.py-2   { padding-top: var(--space-2); padding-bottom: var(--space-2); }
.text-center { text-align: center; }
.text-right  { text-align: right; }
.text-left   { text-align: left; }
.flex-wrap          { display: flex; flex-wrap: wrap; }
.flex-col           { display: flex; flex-direction: column; }
.inline-flex-center { display: inline-flex; align-items: center; }
.shrink-0           { flex-shrink: 0; }
.flex-1             { flex: 1; }
.justify-between    { justify-content: space-between; }
.justify-center     { justify-content: center; }
.contents { display: contents; }
.opacity-30 { opacity: 0.3; }
.opacity-50 { opacity: 0.5; }
.list-none { list-style: none; }
.valign-middle { vertical-align: middle; }
.table-collapse { border-collapse: collapse; }
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
}
.font-medium { font-weight: var(--light-bold); }
.font-bold   { font-weight: 700; }
.italic      { font-style: italic; }
.nowrap      { white-space: nowrap; }
.truncate  { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.break-all { word-break: break-all; }
.leading-normal  { line-height: 1.5; }
.leading-relaxed { line-height: 1.6; }
.pt-2 { padding-top: var(--space-2); }
.pt-3 { padding-top: var(--space-3); }
.form-select { padding: var(--space-1) var(--space-2); border-radius: var(--radius-sm); border: 1px solid var(--border); }
.btn-reset { background: none; border: none; padding: 0; }
.btn-xs { border: 1px solid var(--border); padding: var(--space-1-5) var(--space-3); border-radius: var(--radius); }
.btn-sm { padding: var(--space-1-5) var(--space-4); }
.btn-expand { padding: var(--space-px) var(--space-1-5); }
.expand-chevron {
  display: inline-block;
  transition: transform var(--transition-fast);
  line-height: 1;
}
.expand-chevron--open {
  transform: rotate(90deg);
}
.text-healthy  { color: var(--status-healthy); }
.text-warning  { color: var(--status-warning); }
.text-critical { color: var(--status-critical); }
.text-primary  { color: var(--text-primary); }
.surface-elevated { background: var(--bg-elevated); border: 1px solid var(--border); }
.surface-elevated-card {
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  padding: var(--space-2) var(--space-3);
  border-radius: var(--radius-lg);
}
.link-accent { color: var(--accent); text-decoration: none; }
.cell-pad      { padding: var(--space-1) var(--space-2-5); }
.cell-pad-wide { padding: var(--space-1) var(--space-3); }
.border-b        { border-bottom: 1px solid var(--border); }
.border-b-subtle { border-bottom: 1px solid var(--border-subtle); }
.border-t        { border-top: 1px solid var(--border); }
.chip-badge {
  background: var(--bg-elevated);
  border: 1px solid var(--border-subtle);
}
.chip-accent {
  background: var(--accent-alpha-10);
  color: var(--accent);
}
.chip-accent-muted {
  background: var(--accent-muted);
  color: var(--accent-hover);
}
.chip-healthy {
  background: var(--status-healthy-muted, rgba(34, 197, 94, 0.12));
  color: var(--status-healthy);
}
.dot-sm,
.dot-xs {
  border-radius: var(--radius-full);
  display: inline-block;
  flex-shrink: 0;
}
.dot-sm { width: 8px; height: 8px; }
.dot-xs { width: 6px; height: 6px; }
.badge-warning {
  color: var(--status-warning);
  background: var(--bg-status-warning);
  padding: var(--space-px) var(--space-1-5);
  border-radius: var(--radius-pill);
}
.section-rail {
  background: var(--bg-card);
  border-left: 3px solid var(--section-rail-color, var(--border-accent));
}
summary.section-rail {
  padding: var(--space-3) var(--space-5);
  transition: background var(--transition-fast);
}
.section-rail-body {
  padding: var(--space-4) var(--space-5) var(--space-5);
}
.section-rail-chevron {
  color: var(--section-rail-color, var(--border-accent));
  transition: transform var(--transition-medium);
}
.workflow-graph-container { height: var(--workflow-graph-height, 600px); }
.workflow-node {
  width: 220px;
  height: 120px;
  border: 2px solid #d1d5db;
  border-radius: var(--radius-lg);
  background: #f9fafb;
  padding: var(--space-3);
  font-size: var(--font-size-xs);
}
.workflow-node--score-high { border-color: #16a34a; background: #dcfce7; }
.workflow-node--score-mid  { border-color: #ca8a04; background: #fef9c3; }
.workflow-node--score-low  { border-color: #dc2626; background: #fee2e2; }
