});import { Hono } from 'hono';
import { computeMultiAgentEvaluation } from '../../../../dist/lib/quality/quality-multi-agent.js';
import { sanitizeErrorForResponse } from '../../../../dist/lib/errors/error-sanitizer.js';
import { loadTracesBySessionId, loadEvaluationsByTraceIds } from '../data-loader.js';
import { queryTraces } from '../../../../dist/tools/query-traces.js';
import type { StepScore } from '../../../../dist/backends/index.js';
import { VALID_PERIODS, MAX_IDS, KNOWN_SOURCE_TYPES, HttpStatus, SCORE_DISPLAY_PRECISION, TIME_MS, ErrorMessage } from '../../lib/constants.js';
import { HOOK_NAME, incrementCount, OTEL_STATUS_ERROR_CODE, PARAM_ID_RE, NANOS_TO_MS, attrStr, attrNum, spanAttr, toDateOnly, isValidParam } from '../api-constants.js';
import { buildWorkflowGraph } from '../../lib/workflow-graph.js';
const LIMIT_AGENT_SPANS = 1000;
type AgentAcc = {
  invocations: number;
  errors: number;
  rateLimitCount: number;
  totalOutputSize: number;
  sessions: Set<string>;
  traceIds: Set<string>;
  sourceTypes: Record<string, number>;
  dailyCounts: number[];
};
function computeEvalMetricSummary(scores: number[]): { avg: number; min: number; max: number; count: number } {
  const sorted = [...scores].sort((a, b) => a - b);
  return {
    avg: +(sorted.reduce((a, b) => a + b, 0) / sorted.length).toFixed(SCORE_DISPLAY_PRECISION),
    min: +sorted[0].toFixed(SCORE_DISPLAY_PRECISION),
    max: +sorted[sorted.length - 1].toFixed(SCORE_DISPLAY_PRECISION),
    count: sorted.length,
  };
}
function createAgentAccumulator(periodDays: number): AgentAcc {
  return {
    invocations: 0,
    errors: 0,
    rateLimitCount: 0,
    totalOutputSize: 0,
    sessions: new Set(),
    traceIds: new Set(),
    sourceTypes: Object.create(null),
    dailyCounts: new Array(periodDays).fill(0),
  };
}
export const agentRoutes = new Hono();
agentRoutes.get('/agents', async (c) => {
  const periodParam = c.req.query('period') ?? '30d';
  const periodDays = VALID_PERIODS[periodParam];
  if (periodDays === undefined) {
    return c.json({ error: `Invalid period value. Must be one of: ${Object.keys(VALID_PERIODS).join(', ')}` }, HttpStatus.BadRequest);
  }
  const now = new Date();
  const endDate = toDateOnly(now);
  const startDate = toDateOnly(new Date(now.getTime() - periodDays * TIME_MS.DAY));
  try {
    const result = await queryTraces({
      attributeFilter: { 'hook.name': HOOK_NAME.AGENT_POST_TOOL },
      startDate,
      endDate,
      limit: LIMIT_AGENT_SPANS,
    });
    const dateBuckets: string[] = [];
    for (let d = 0; d < periodDays; d++) {
      const day = new Date(now.getTime() - (periodDays - 1 - d) * TIME_MS.DAY);
      dateBuckets.push(toDateOnly(day));
    }
    const bucketIndex = new Map(dateBuckets.map((b, i) => [b, i]));
    const acc: Record<string, AgentAcc> = Object.create(null);
    const traceToAgents = new Map<string, Set<string>>();
    for (const span of result.traces) {
      const name = attrStr(span, 'gen_ai.agent.name');
      const entry = (acc[name] ??= createAgentAccumulator(periodDays));
      entry.invocations++;
      if (span.startTimeUnixNano) {
        const dayKey = toDateOnly(new Date(span.startTimeUnixNano / NANOS_TO_MS));
        const idx = bucketIndex.get(dayKey);
        if (idx !== undefined) entry.dailyCounts[idx]++;
      }
      if (spanAttr(span, 'agent.has_error', 'boolean')) entry.errors++;
      if (spanAttr(span, 'agent.has_rate_limit', 'boolean')) entry.rateLimitCount++;
      entry.totalOutputSize += attrNum(span, 'agent.output_size');
      const sid = attrStr(span, 'session.id', '');
      if (sid) entry.sessions.add(sid);
      if (span.traceId) {
        entry.traceIds.add(span.traceId);
        let agentSet = traceToAgents.get(span.traceId);
        if (!agentSet) traceToAgents.set(span.traceId, agentSet = new Set());
        agentSet.add(name);
      }
      const rawSrc = attrStr(span, 'agent.source_type');
      const src = KNOWN_SOURCE_TYPES.has(rawSrc) ? rawSrc : 'other';
      incrementCount(entry.sourceTypes, src);
    }
    const allTraceIds = [...traceToAgents.keys()];
    const evaluations = await loadEvaluationsByTraceIds(allTraceIds, startDate, endDate);
    const agentEvalAcc: Record<string, Record<string, number[]>> = Object.create(null);
    for (const ev of evaluations) {
      if (!ev.traceId || ev.scoreValue == null || !Number.isFinite(ev.scoreValue)) continue;
      const agentNames = traceToAgents.get(ev.traceId);
      if (!agentNames) continue;
      for (const agent of agentNames) {
        const metrics = (agentEvalAcc[agent] ??= Object.create(null));
        (metrics[ev.evaluationName] ??= []).push(ev.scoreValue);
      }
    }
    const agents = Object.entries(acc).map(([agentName, d]) => {
      const evalMetrics = agentEvalAcc[agentName] ?? {};
      const evalSummary: Record<string, { avg: number; min: number; max: number; count: number }> = {};
      for (const [metric, scores] of Object.entries(evalMetrics)) {
        evalSummary[metric] = computeEvalMetricSummary(scores);
      }
      const sessionIdList = [...d.sessions];
      const traceIdList = [...d.traceIds];
      return {
        agentName,
        invocations: d.invocations,
        errors: d.errors,
        errorRate: d.invocations > 0 ? +(d.errors / d.invocations).toFixed(SCORE_DISPLAY_PRECISION) : 0,
        rateLimitCount: d.rateLimitCount,
        avgOutputSize: d.invocations > 0 ? Math.round(d.totalOutputSize / d.invocations) : 0,
        sessionCount: d.sessions.size,
        sessionIds: sessionIdList.slice(0, MAX_IDS),
        sessionIdsTruncated: sessionIdList.length > MAX_IDS,
        traceIdsTotal: traceIdList.length,
        traceIds: traceIdList.slice(0, MAX_IDS),
        traceIdsTruncated: traceIdList.length > MAX_IDS,
        sourceTypes: d.sourceTypes,
        dailyCounts: d.dailyCounts,
        evalSummary,
      };
    }).sort((a, b) => b.invocations - a.invocations);
    return c.json({ period: periodParam, startDate, endDate, agents });
  } catch (err) {
    return c.json({ error: sanitizeErrorForResponse(err) }, HttpStatus.InternalServerError);
  }
});
agentRoutes.get('/agents/:sessionId', async (c) => {
  const sessionId = c.req.param('sessionId');
  if (!isValidParam(sessionId, PARAM_ID_RE)) {
    return c.json({ error: ErrorMessage.InvalidSessionIdFormat }, HttpStatus.BadRequest);
  }
  try {
    const spans = await loadTracesBySessionId(sessionId);
    const agentMap = new Map<number, string>();
    const traceIds = new Set<string>();
    spans.forEach((span, i) => {
      const agent = attrStr(span, 'agent.name', '') || attrStr(span, 'gen_ai.agent.name', '') || undefined;
      if (agent) agentMap.set(i, agent);
      if (span.traceId) traceIds.add(span.traceId);
    });
    const stepScores: StepScore[] = spans.map((span, i) => ({
      step: i,
      score: attrNum(span, 'evaluation.score', span.status?.code === OTEL_STATUS_ERROR_CODE ? 0 : 1),
      explanation: span.name,
    }));
    const evalPromise = loadEvaluationsByTraceIds([...traceIds]);
    const evaluation = computeMultiAgentEvaluation(stepScores, agentMap);
    const evaluations = await evalPromise;
    const serializedAgentMap = Object.fromEntries(agentMap);
    const graph = buildWorkflowGraph(evaluation, spans);
    return c.json({
      sessionId,
      spans,
      evaluation,
      evaluations,
      agentMap: serializedAgentMap,
      graph,
    });
  } catch (err) {
    return c.json({ error: sanitizeErrorForResponse(err) }, HttpStatus.InternalServerError);
  }
});import { Hono } from 'hono';
import { sanitizeErrorForResponse } from '../../../../dist/lib/errors/error-sanitizer.js';
import {
  computeRollingDegradationSignals,
  type DegradationState,
} from '../../../../dist/lib/quality/quality-feature-engineering.js';
import {
  DEFAULT_BIN_COUNT,
} from '../../../../dist/lib/quality/quality-constants.js';
import {
  buildEvenBucketBoundaries,
  getEvenBucketIndex,
} from '../../../../dist/lib/quality/bucket-utils.js';
import { loadEvaluationsByMetric } from '../data-loader.js';
import { LIVE_WINDOW_MS, EVAL_LIMIT, HttpStatus, PeriodSchema, ErrorMessage, computePeriodDates } from '../../lib/constants.js';
import type { LiveMetric, QualityLiveData } from '../../types.js';
export const qualityRoutes = new Hono();
qualityRoutes.get('/quality/live', async (c) => {
  try {
    const now = new Date();
    const start = new Date(now.getTime() - LIVE_WINDOW_MS);
    const evaluationsByMetric = await loadEvaluationsByMetric(
      start.toISOString(),
      now.toISOString(),
    );
    const metrics: LiveMetric[] = [];
    const sessionIds = new Set<string>();
    let latestTimestamp = '';
    for (const [name, evals] of evaluationsByMetric) {
      const sorted = evals
        .slice()
        .sort((a, b) => b.timestamp.localeCompare(a.timestamp))
        .slice(0, EVAL_LIMIT);
      for (const ev of sorted) {
        if (ev.traceId) sessionIds.add(ev.traceId);
      }
      const latest = sorted[0];
      if (latest && latest.scoreValue != null) {
        metrics.push({
          name,
          score: latest.scoreValue,
          evaluatorType: latest.evaluatorType ?? 'unknown',
          timestamp: latest.timestamp,
        });
        if (latest.timestamp > latestTimestamp) {
          latestTimestamp = latest.timestamp;
        }
      }
    }
    metrics.sort((a, b) => a.name.localeCompare(b.name));
    const response: QualityLiveData = {
      metrics,
      sessionCount: sessionIds.size,
      lastUpdated: latestTimestamp || now.toISOString(),
    };
    return c.json(response);
  } catch (err) {
    return c.json({ error: sanitizeErrorForResponse(err) }, HttpStatus.InternalServerError);
  }
});
qualityRoutes.get('/degradation-signals', async (c) => {
  const periodResult = PeriodSchema.safeParse(c.req.query('period'));
  if (!periodResult.success) {
    return c.json({ error: ErrorMessage.InvalidPeriod }, HttpStatus.BadRequest);
  }
  try {
    const period = periodResult.data;
    const { start: startDate, end: endDate } = computePeriodDates(period);
    const startMs = new Date(startDate).getTime();
    const endMs = new Date(endDate).getTime();
    const bucketMs = (endMs - startMs) / DEFAULT_BIN_COUNT;
    const boundaries = buildEvenBucketBoundaries(startMs, endMs, DEFAULT_BIN_COUNT);
    const evaluationsByMetric = await loadEvaluationsByMetric(startDate, endDate);
    const metricNames = [...evaluationsByMetric.keys()];
    const bucketLabels = boundaries.map(b => ({
      startTime: new Date(b.start).toISOString(),
      endTime: new Date(b.end).toISOString(),
    }));
    const timeBuckets: Record<string, Array<{ scores: number[]; startTime: string; endTime: string }>> = {};
    for (const [name, evals] of evaluationsByMetric) {
      const buckets = bucketLabels.map(b => ({ ...b, scores: [] as number[] }));
      for (const ev of evals) {
        if (ev.scoreValue == null) continue;
        const ts = new Date(ev.timestamp).getTime();
        const idx = getEvenBucketIndex(ts, startMs, bucketMs, DEFAULT_BIN_COUNT);
        if (idx !== null) buckets[idx].scores.push(ev.scoreValue);
      }
      timeBuckets[name] = buckets;
    }
    const noBreachState: DegradationState = { lastRun: '', breaches: {} };
    const window = { startDate, endDate };
    const reports = computeRollingDegradationSignals(timeBuckets, metricNames, noBreachState, window);
    return c.json({ period, reports, computedAt: new Date().toISOString() });
  } catch (err) {
    return c.json({ error: sanitizeErrorForResponse(err) }, HttpStatus.InternalServerError);
  }
});import { MultiDirectoryBackend } from '../../../dist/backends/local-jsonl.js';
import type { EvaluationResult } from '../../../dist/backends/index.js';
import { queryVerifications as queryVerificationsLib, type HumanVerificationEvent } from '../../../dist/lib/audit/verification-events.js';
import { queryTraces as queryTracesTool } from '../../../dist/tools/query-traces.js';
import { queryLogs } from '../../../dist/tools/query-logs.js';
import { TIME_MS, PERIOD_MS } from '../lib/constants.js';
import { toDateOnly } from './api-constants.js';
import { groupBy } from '../lib/quality-utils.js';
const DEFAULT_LOOKBACK_7D = PERIOD_MS['7d'];
const DEFAULT_LOOKBACK_30D = PERIOD_MS['30d'];
const DEFAULT_LOOKBACK_90D = 90 * TIME_MS.DAY;
const LIMIT_EVALS_BULK = 100_000;
const LIMIT_EVALS_METRIC = 10_000;
const LIMIT_EVALS_PER_TRACE = 1_000;
const LIMIT_EVALS_SESSION = 10_000;
const LIMIT_TRACES = 500;
const LIMIT_LOGS = 1_000;
const LIMIT_HEALTH_PROBE = 1;
let backend: MultiDirectoryBackend | undefined;
function getBackend(): MultiDirectoryBackend {
  if (!backend) {
    backend = new MultiDirectoryBackend(undefined, true);
  }
  return backend;
}
function defaultRange(lookbackMs: number): { start: string; end: string } {
  const now = new Date();
  return {
    start: new Date(now.getTime() - lookbackMs).toISOString(),
    end: now.toISOString(),
  };
}
export async function loadEvaluationsByMetric(
  start: string,
  end: string
): Promise<Map<string, EvaluationResult[]>> {
  const be = getBackend();
  const evals = await be.queryEvaluations({ startDate: start, endDate: end, limit: LIMIT_EVALS_BULK });
  return groupBy(evals, ev => ev.evaluationName);
}
export async function loadEvaluationsForMetric(
  metricName: string,
  start: string,
  end: string
): Promise<EvaluationResult[]> {
  const be = getBackend();
  return be.queryEvaluations({
    startDate: start,
    endDate: end,
    evaluationName: metricName,
    limit: LIMIT_EVALS_METRIC,
  });
}
export async function loadEvaluationsByTraceId(
  traceId: string,
  startDate?: string,
  endDate?: string,
): Promise<EvaluationResult[]> {
  const be = getBackend();
  const { start, end } = defaultRange(DEFAULT_LOOKBACK_90D);
  return be.queryEvaluations({
    traceId,
    startDate: startDate ?? start,
    endDate: endDate ?? end,
    limit: LIMIT_EVALS_PER_TRACE,
  });
}
const TRACE_QUERY_CONCURRENCY = 10;
export async function loadEvaluationsByTraceIds(
  traceIds: string[],
  startDate?: string,
  endDate?: string
): Promise<EvaluationResult[]> {
  const uniqueIds = [...new Set(traceIds)];
  if (uniqueIds.length === 0) return [];
  const be = getBackend();
  const { start: defStart, end: defEnd } = defaultRange(DEFAULT_LOOKBACK_90D);
  const start = startDate ?? defStart;
  const end = endDate ?? defEnd;
  const all: EvaluationResult[] = [];
  for (let i = 0; i < uniqueIds.length; i += TRACE_QUERY_CONCURRENCY) {
    const batch = uniqueIds.slice(i, i + TRACE_QUERY_CONCURRENCY);
    const settled = await Promise.allSettled(
      batch.map(traceId => be.queryEvaluations({ traceId, startDate: start, endDate: end, limit: LIMIT_EVALS_PER_TRACE }))
    );
    for (const result of settled) {
      if (result.status === 'fulfilled') all.push(...result.value);
    }
  }
