export function scoreColorBand(
  value: number,
  direction: ScoreDirection = 'maximize',
): ScoreColorBand {
  const v = direction === 'minimize' ? 1 - value : value;
  if (v >= 0.9) return 'excellent';
  if (v >= 0.8) return 'good';
  if (v >= 0.6) return 'adequate';
  if (v >= 0.4) return 'poor';
  return 'failing';
}
