const SCORE_BANDS = {
  HIGH: { min: WORKFLOW_SCORE_HIGH_MIN, label: 'Good', className: 'workflow-node--score-high' },
  MID: { min: WORKFLOW_SCORE_MID_MIN, label: 'Fair', className: 'workflow-node--score-mid' },
