export function buildWorkflowGraph(
  evaluation: MultiAgentEvaluation | null,
  spans: TraceSpan[],
): WorkflowGraph {
  if (evaluation !== null && Array.isArray(evaluation.turns)) {
    return buildFromEvaluation(evaluation, spans);
  }
  return inferFromSpans(spans);
